  ('dietitian-moex-01043', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '對第1型糖尿病患者之處置，下列何者較適當？', '["減少食物的攝取", "需要大量注射胰島素", "少量多餐攝取含醣類食物", "若未進食，則不必注射insulin"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01044', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '引起糖尿病人低血糖現象的原因，不包括下列何者？', '["進食過多", "運動過久", "誤餐", "過多的胰島素或口服降血糖藥物"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01045', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '具有下列那些風險因子的成年人，建議考慮執行糖尿病篩檢？①一等親有糖尿病  ②高血壓且', '["三酸甘油酯超過 150 mg/dL", "低密度脂蛋白-膽固醇超過 130 mg/dL ⑤曾經被診斷為GDM", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01046', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '下列有關升糖指數（GI）的近期研究結果及討論，何者錯誤？', '["Wheeler等人於2012年系統性的回顧研究發現，「低-GI」和「高-GI」飲食對血糖及心血管疾 病風險的控制沒有差異", "Ma等人及Wolever等人於2008年的兩個研究均發現，「低-GI」和「高-GI」飲食對A1C值沒 有明顯差異", "臨床上針對GI值的研究，發現針對某一特定含醣類食物，在不同受試者體內的反應有其一致性", "大多數人們的飲食，都屬於中等GI值，目前無法得知，飲食降低多少GI值會改善血糖的控制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01047', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '針對妊娠糖尿病MNT的敘述，下列何者錯誤？', '["一日所需醣類應分配至三正餐及2~4次點心", "每日醣類量應至少提供175公克", "對於肥胖的GDM個案，不建議限制熱量，以避免影響胎兒生長", "應有「睡前點心」以預防夜間的酮酸血症（ketosis）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01048', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '張先生被診斷有慢性腎臟疾病，eGFR24mL/min，urineoutput1,500mL，血壓145/90mmHg，血液 生化值如下（括弧內數值為正常值範圍）：BUN65（7~20）mg/dL、creatinine3.2（0.5~1.3）mg/dL、 potassium4.5（3.5~5.5）mEq/L、phosphorus4.9（2.3~5.1）mg/dL，有關他的飲食治療建議，下列 何者錯誤？', '["應降低蛋白質攝取量", "應降低鉀的攝取量", "應降低磷的攝取量", "應降低鈉的攝取量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01049', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '維持透析患者血磷濃度正常，除飲食需限制磷的攝取量外，尚需配合使用磷結合劑，下列何者不 建議使用？', '["Calciumcarbonate", "Lanthanumcarbonate", "Calciumcitrate", "Calciumacetate"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01050', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '評估腎功能的指標包括血液當中的尿素氮（BUN）和肌酸酐（Cr），當這兩者的比例大於 20 時 （BUN/Cr>20）時，常用來診斷為下列何種腎臟疾病？', '["腎絲球腎炎", "急性腎小管壞死", "腎前性急性腎損傷", "腎後性急性腎損傷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01051', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '王小姐36歲，因紅斑性狼瘡導致的腎病變而進行腹膜透析，身高162公分、近半年體重約為55公 斤，血液生化值如下：BUN52mg/dL、Cr4.1mg/dL、albumin3.3g/dL、Na135mEq/L、K2.3mEq/L、 triglyceride350mg/dL、nPNA0.7、Kt/V1.1，對於此病人的營養建議何者錯誤？', '["應攝取至少50%高生理價蛋白質", "應限制含糖飲料的攝取", "蛋白質攝取量為66~82.5公克", "應限制蔬菜水果攝取，以控制鉀離子"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-01052', 'dietitian', 'dietitian-moex-111-2755cf97', 'sub-dietitian-05', NULL, 'single_choice', '有關心臟衰竭病人，鈉及水分的攝取建議，下列敘述何者錯誤？', '["每日鈉攝取建議小於2公克", "一般水分攝取建議每天以2,000毫升為限", "減少加工、醃漬、濃縮的食品及調味品", "病人若血清鈉偏低，建議飲食暫時不需限制鹽分攝取"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:53+00:00", "source_pdf_sha1": "e3564b4d13aa", "answer_pdf_sha1": "08ee67449858", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "103", "s": "0203", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "膳食療養學", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
